parameters.jsCode:
const msjs = $input.first().json.messages;

if (!msjs || msjs.length === 0) return [{ json: { message: "" } }];

// Parseamos cada mensaje y extraemos solo la propiedad 'text'
const texts = msjs.map(item => {
  try {
    return JSON.parse(item).text;
  } catch (e) {
    return item;
  }
});

// Los unimos (reverse para que mantengan el orden cronológico si el buffer los guardó al revés)
const merged = texts.reverse().join(' ');

return [
  {
    json: {
      message: merged
    }
  }
];

