parameters.jsCode:
// 1. Datos de entrada
const agentesDisponibles = $('Get Advisors').all().map(i => i.json);
const historialLeads = $('Get Leads').all().map(i => i.json);
const aiOutput = $('AI Agent').first().json.output;
const userData = $('Normalize').first().json;

// Usamos el valor del Switch o del AI Agent, asegurando limpieza
const verticalActual = ($('Switch').first().json.output.vertical || "").trim();

// 2. Filtrar agentes de la vertical (Aseguramos que la columna en Agentes se llame 'Vertical' y 'Nombre')
const poolAgentes = agentesDisponibles.filter(a => 
    (a.Vertical || "").trim().toLowerCase() === verticalActual.toLowerCase()
);

if (poolAgentes.length === 0) throw new Error(`Sin agentes para: ${verticalActual}`);

// 3. SORT por row_number (Mucho más seguro que fechas)
// Asumimos que la propiedad se llama 'row_number' o la mapeaste así
const leadsOrdenados = historialLeads.sort((a, b) => {
    return (Number(b.row_number) || 0) - (Number(a.row_number) || 0);
});

// 4. Lógica de rotación
const ultimoLead = leadsOrdenados.length > 0 ? leadsOrdenados[0] : null;
let proximoAgente;

if (!ultimoLead || !ultimoLead.asesor) {
    proximoAgente = poolAgentes[0];
} else {
    const nombreUltimo = ultimoLead.asesor.trim().toLowerCase();

    // Buscamos en poolAgentes (la columna en la hoja de Agentes debe ser 'Nombre')
    const ultimoIndex = poolAgentes.findIndex(a => 
        (a.Nombre || "").trim().toLowerCase() === nombreUltimo
    );

    const proximoIndex = (ultimoIndex === -1 || ultimoIndex >= poolAgentes.length - 1) ? 0 : ultimoIndex + 1;
    proximoAgente = poolAgentes[proximoIndex];
}

// 5. Salida: Mapeamos los nombres EXACTOS de tus columnas de la hoja Leads
return [{
    json: {
        agente: proximoAgente,
        lead_data: {
            fecha: DateTime.now().setZone('America/Argentina/Buenos_Aires').toFormat('dd/LL/yyyy HH:mm:ss'),
            nombre: aiOutput.nombre,
            telefono: userData.phone,
            vertical: verticalActual,
            asesor: proximoAgente.Nombre,
            motivo: $('Switch').first().json.output.motivo || "Sin especificar",
            mensaje: aiOutput.motivo
        },
        respuesta_whatsapp: `${aiOutput.respuesta_al_cliente} *${proximoAgente.Nombre}*  se pondrá en contacto con a la brevedad.` 
    }
}];

// Obtener log previo
const previousLog = $json.conversation_log || [];

// Función para formatear fecha DD/MM/YYYY HH:mm:ss
function formatDate(date) {
  const d = new Date(date);

  const pad = (n) => n.toString().padStart(2, '0');

  return `${pad(d.getDate())}/${pad(d.getMonth() + 1)}/${d.getFullYear()} ${pad(d.getHours())}:${pad(d.getMinutes())}:${pad(d.getSeconds())}`;
}

// Timestamp actual
const now = formatDate(new Date());

// Nuevos mensajes
const newEntries = [];

if ($json.Usuario) {
  newEntries.push({
    role: "user",
    message: $json.Usuario.trim(),
    timestamp: now
  });
}

if ($json.Agente) {
  newEntries.push({
    role: "assistant",
    message: $json.Agente.trim(),
    timestamp: now
  });
}

// Retorno final
return [
  {
    json: {
      Nombre: $json.Nombre,
      conversation_log: [...previousLog, ...newEntries]
    }
  }
];

