=<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body {
      font-family: Arial, sans-serif;
      background-color: #f4f4f4;
      padding: 20px;
    }
    .container {
      max-width: 600px;
      margin: auto;
      background: #ffffff;
      padding: 20px;
      border-radius: 8px;
    }
    .title {
      font-size: 20px;
      font-weight: bold;
      margin-bottom: 20px;
    }
    .message {
      margin-bottom: 15px;
      padding: 10px;
      border-radius: 6px;
    }
    .user {
      background-color: #e1f5fe;
      text-align: left;
    }
    .assistant {
      background-color: #e8f5e9;
      text-align: left;
    }
    .role {
      font-weight: bold;
      margin-bottom: 5px;
    }
    .timestamp {
      font-size: 11px;
      color: #777;
      margin-top: 5px;
    }
  </style>
</head>

<body>
  <div class="container">
    <div class="title">Nueva conversación recibida</div>

    {{ $json.conversation_log.map(m => `
      <div class="message ${m.role}">
        <div class="role">
          ${m.role === 'user' ? '👤 Usuario' : '🤖 Asistente'}
        </div>
        <div>${m.message}</div>
        <div class="timestamp">${m.timestamp}</div>
      </div>
    `).join('') }}

  </div>
</body>
</html>
